diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..3f14d41291cc 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1516,6 +1516,7 @@ static Instruction *foldBoxMultiply(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Value *V = simplifyAddInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -1564,6 +1565,51 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Ty->isIntOrIntVectorTy(1))
     return BinaryOperator::CreateXor(LHS, RHS);

+  // Fold ceil-udiv-by-power-of-2 idiom:
+  // (X >> C) + zext((X & ((1 << C) - 1)) != 0) --> (X + ((1 << C) - 1)) >> C
+  {
+    auto MatchCeilUDivPow2 = [&](Value *ShiftV, Value *IncV) -> Instruction * {
+      Value *X, *AndX, *MaskedV, *CmpRHS;
+      const APInt *ShAmt, *Mask;
+      CmpPredicate Pred;
+
+      if (!match(ShiftV, m_LShr(m_Value(X), m_APInt(ShAmt))))
+        return nullptr;
+
+      if (!match(IncV, m_ZExt(m_ICmp(Pred, m_Value(MaskedV), m_Value(CmpRHS)))))
+        return nullptr;
+
+      if (Pred != ICmpInst::ICMP_NE)
+        return nullptr;
+
+      if (!match(CmpRHS, m_Zero()))
+        return nullptr;
+
+      if (!match(MaskedV, m_And(m_Value(AndX), m_APInt(Mask))))
+        return nullptr;
+
+      if (AndX != X)
+        return nullptr;
+
+      unsigned BitWidth = cast<IntegerType>(Ty->getScalarType())->getBitWidth();
+      if (ShAmt->uge(BitWidth))
+        return nullptr;
+
+      APInt ExpectedMask =
+          APInt::getLowBitsSet(Mask->getBitWidth(), ShAmt->getZExtValue());
+      if (*Mask != ExpectedMask)
+        return nullptr;
+
+      auto *Add = BinaryOperator::CreateAdd(X, ConstantInt::get(Ty, *Mask));
+      return BinaryOperator::CreateLShr(Add, ConstantInt::get(Ty, *ShAmt));
+    };
+
+    if (Instruction *R = MatchCeilUDivPow2(LHS, RHS))
+      return R;
+    if (Instruction *R = MatchCeilUDivPow2(RHS, LHS))
+      return R;
+  }
+
   // X + X --> X << 1
   if (LHS == RHS) {
     auto *Shl = BinaryOperator::CreateShl(LHS, ConstantInt::get(Ty, 1));
@@ -1730,10 +1776,10 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (match(&I,
             m_c_Add(m_OneUse(m_Not(m_OneUse(m_Mul(m_Value(A), m_APInt(C1))))),
                     m_Deferred(A)))) {
-    Type *Ty = I.getType();
-    Constant *NewMulC = ConstantInt::get(Ty, 1 - *C1);
+    Type *Ty2 = I.getType();
+    Constant *NewMulC = ConstantInt::get(Ty2, 1 - *C1);
     Value *NewMul = Builder.CreateMul(A, NewMulC);
-    return BinaryOperator::CreateAdd(NewMul, ConstantInt::getAllOnesValue(Ty));
+    return BinaryOperator::CreateAdd(NewMul, ConstantInt::getAllOnesValue(Ty2));
   }

   // (A * -2**C) + B --> B - (A << C)
@@ -1893,6 +1939,7 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Eliminate an op from a linear interpolation (lerp) pattern.
 static Instruction *factorizeLerp(BinaryOperator &I,
                                   InstCombiner::BuilderTy &Builder) {
